<template>
    <div  ref="charts" style="height:100%;width:1000px;"></div>
</template>
  
<script setup>

import { onMounted, reactive, ref, watch } from "vue-demi";
import { useChartsStore} from "../../../store/modules/chartsValue"

import * as echarts from 'echarts';
let chartsStore = useChartsStore();
let chartDom;

const charts = ref(null);
let option = {
    xAxis: {
    type: 'category',
    data: [],
    
  },
  yAxis: {
    type: 'value',
   
  },
  tooltip:{
    trigger: "axis",
  },
  series: [
    {
      data: [],
      type: 'line',
    }
  ]
}

watch(
  () => chartsStore.pressureData,
  (val) => {
    let time_list = []
    let pressure_list = []
    for(let i = 0; i < val.length; i+=1 ){
      time_list.push(val[i]['time'])
      pressure_list.push(val[i]['pressure'])
    }
    option.xAxis.data = time_list
    option.series[0].data = pressure_list
    reDraw();
  }
);

const reDraw = () => {
  chartDom.setOption(option);
  chartDom.resize();
};
  
onMounted(() => {
    chartDom = echarts.init(charts.value);
    reDraw();
  });
</script>
  
